import { HttpClient } from "@angular/common/http";
import {
  Component,
  Inject,
  EventEmitter,
  Input,
  OnInit,
  Output,
  ViewChild,
} from "@angular/core";
import { DatePipe } from "@angular/common";
import { format, getMonth, parse } from "date-fns";
import { Capacitor } from "@capacitor/core";
import { DOCUMENT } from "@angular/common";
import { AlertController, ModalController } from "@ionic/angular";
import {
  FormBuilder,
  FormGroup,
  FormControl,
  Validators,
} from "@angular/forms";
import { EnvService } from "src/app/core/services/env.service";
import { User } from "../../../Models/Permissions/User";
import { Permission } from "../../../Models/Permissions/Permission";
import { OverlayEventDetail } from "@ionic/core/components";
import { TranslateService } from "@ngx-translate/core";
import { pagingService } from "src/app/core/services/paging.service";
import { AlertService } from "src/app/core/services/alert.service";

@Component({
  selector: "UserPermissions",
  templateUrl: "./user-permissions.page.html",
  styleUrls: ["./user-permissions.page.scss"],
})
export class UserPermissionsPage implements OnInit {
  showLoader: boolean = false;
  initialLoad: boolean = true;

  days: string[][];
  permissions: Permission[] = [];
  selectedUser: User;
  permissionTimeForm: FormGroup;
  permissionDateForm: FormGroup;

  selectedPermission: Permission;
  selectedAllPermissions: boolean;
  isDateModalOpen: boolean;
  isTimeModalOpen: boolean;

  userPage: number = 1;

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private alertController: AlertController,
    private modal: ModalController,
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    public translate: TranslateService,
    public pagingService: pagingService,
    public alertService: AlertService,
    @Inject(DOCUMENT) private document: Document
  ) {}

  async ngOnInit() {
    this.days = [
      [await this.translate.get("days.saturday").toPromise(), "1"],
      [await this.translate.get("days.sunday").toPromise(), "2"],
      [await this.translate.get("days.monday").toPromise(), "3"],
      [await this.translate.get("days.tuesday").toPromise(), "4"],
      [await this.translate.get("days.wednesday").toPromise(), "5"],
      [await this.translate.get("days.thursday").toPromise(), "6"],
      [await this.translate.get("days.friday").toPromise(), "7"],
    ];
    this.permissionDateForm = this.formBuilder.group({
      startDate: ["", [Validators.required]],
      endDate: ["", [Validators.required]],
      workingDays: [""],
    });
    this.permissionTimeForm = this.formBuilder.group({
      startTime: ["", [Validators.required]],
      endTime: ["", [Validators.required]],
    });
  }

  ngOnDestroy(): void {}

  userSelected(user: User): void {
    this.selectedUser = user;
    this.showLoader = true;
    this.http
      .post<Permission[]>(
        this.env.API_URL + `api/Permissions/GetUserPermissions`,
        user
      )
      .subscribe({
        next: (data) => {
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  ChangePermission(permission: Permission, value: number): void {
    this.showLoader = true;
    var changedPermission: Permission = {
      feature_description: permission.feature_description,
      feature_name: permission.feature_name,
      feature_number: permission.feature_number,
      feature_type: permission.feature_type,
      permission: value,
      branch_code: permission.branch_code,
      org_code: permission.org_code,
      username: permission.username,
      work_end_date: permission.work_end_date,
      work_start_date: permission.work_start_date,
      working_days: permission.working_days,
      work_start_time: permission.work_start_time,
      work_end_time: permission.work_end_time,
    };
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetUserPermission`,
        changedPermission
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  ChangePermissionDate(permission: Permission): void {
    this.showLoader = true;
    var changedPermission: Permission = {
      feature_description: permission.feature_description,
      feature_name: permission.feature_name,
      feature_number: permission.feature_number,
      feature_type: permission.feature_type,
      permission: permission.permission,
      branch_code: permission.branch_code,
      org_code: permission.org_code,
      username: permission.username,
      work_end_date: this.permissionDateFormControls.endDate.value,
      work_start_date: this.permissionDateFormControls.startDate.value,
      working_days:
        this.permissionDateFormControls.workingDays.value.toString(),
      work_start_time: permission.work_start_time,
      work_end_time: permission.work_end_time,
    };
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetUserPermission`,
        changedPermission
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  ChangePermissionsDate(permissions: Permission[]): void {
    this.showLoader = true;
    var newPermissions: Permission[] = [];
    permissions.forEach((permission) => {
      var changedPermission: Permission = {
        feature_description: permission.feature_description,
        feature_name: permission.feature_name,
        feature_number: permission.feature_number,
        feature_type: permission.feature_type,
        permission: permission.permission,
        branch_code: permission.branch_code,
        org_code: permission.org_code,
        username: permission.username,
        work_end_date: this.permissionDateFormControls.endDate.value,
        work_start_date: this.permissionDateFormControls.startDate.value,
        working_days:
          this.permissionDateFormControls.workingDays.value.toString(),
        work_start_time: permission.work_start_time,
        work_end_time: permission.work_end_time,
      };
      newPermissions.push(changedPermission);
    });
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetUserPermissions`,
        newPermissions
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  ChangePermissionTime(permission: Permission): void {
    this.showLoader = true;
    console.log(
      parse(
        this.permissionTimeFormControls.startTime.value,
        "hh:mm",
        new Date()
      )
    );
    console.log(this.permissionTimeFormControls.startTime.value);
    var changedPermission: Permission = {
      feature_description: permission.feature_description,
      feature_name: permission.feature_name,
      feature_number: permission.feature_number,
      feature_type: permission.feature_type,
      permission: permission.permission,
      branch_code: permission.branch_code,
      org_code: permission.org_code,
      username: permission.username,
      work_end_date: permission.work_end_date,
      work_start_date: permission.work_start_date,
      working_days: permission.working_days,
      work_start_time: this.permissionTimeFormControls.startTime.value,
      work_end_time: this.permissionTimeFormControls.endTime.value,
    };
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetUserPermission`,
        changedPermission
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  ChangePermissionsTime(permissions: Permission[]): void {
    this.showLoader = true;
    var newPermissions: Permission[] = [];
    permissions.forEach((permission) => {
      var changedPermission: Permission = {
        feature_description: permission.feature_description,
        feature_name: permission.feature_name,
        feature_number: permission.feature_number,
        feature_type: permission.feature_type,
        permission: permission.permission,
        branch_code: permission.branch_code,
        org_code: permission.org_code,
        username: permission.username,
        work_end_date: permission.work_end_date,
        work_start_date: permission.work_start_date,
        working_days: permission.working_days,
        work_start_time: this.permissionTimeFormControls.startTime.value,
        work_end_time: this.permissionTimeFormControls.endTime.value,
      };
      newPermissions.push(changedPermission);
    });
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetUserPermissions`,
        newPermissions
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  async ChangePermissions(permissions: Permission[], value: number) {
    this.showLoader = true;
    var newPermissions: Permission[] = [];
    permissions.forEach((permission) => {
      var changedPermission: Permission = {
        feature_description: permission.feature_description,
        feature_name: permission.feature_name,
        feature_number: permission.feature_number,
        feature_type: permission.feature_type,
        permission: value,
        branch_code: permission.branch_code,
        org_code: permission.org_code,
        username: permission.username,
        work_end_date: permission.work_end_date,
        work_start_date: permission.work_start_date,
        working_days: permission.working_days,
        work_start_time: permission.work_start_time,
        work_end_time: permission.work_end_time,
      };
      newPermissions.push(changedPermission);
    });
    var alertText = value == 1 ? "منح" : "إلغاء";
    if (
      permissions.length > 0 &&
      !(await this.alertService.SaveAlert(
        `هل تريد ${alertText} جميع الصلاحيات؟`
      ))
    ) {
      this.showLoader = false;
      return;
    }
    this.http
      .put<Permission[]>(
        this.env.API_URL + `api/Permissions/SetUserPermissions`,
        newPermissions
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.permissions = data["permissions"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  DeselectUser() {
    this.selectedUser = null;
  }

  cancelModal() {
    this.modal.dismiss(null, "cancel");
  }

  confirmModal(date: boolean) {
    this.modal.dismiss(date, "confirm");
  }

  onWillDismiss(event: Event) {
    const ev = event as CustomEvent<OverlayEventDetail<boolean>>;
    if (ev.detail.role === "confirm") {
      if (ev.detail.data == true)
        if (!this.selectedAllPermissions) {
          this.ChangePermissionDate(this.selectedPermission);
        } else {
          this.ChangePermissionsDate(this.permissions);
        }
      else {
        if (!this.selectedAllPermissions) {
          this.ChangePermissionTime(this.selectedPermission);
        } else {
          this.ChangePermissionsTime(this.permissions);
        }
      }
    }
  }

  onDidDismiss(event: Event) {
    const ev = event as CustomEvent<OverlayEventDetail<Permission>>;
    this.permissionDateForm = this.formBuilder.group({
      startDate: ["", [Validators.required]],
      endDate: ["", [Validators.required]],
      workingDays: [""],
    });
    this.permissionTimeForm = this.formBuilder.group({
      startTime: ["", [Validators.required]],
      endTime: ["", [Validators.required]],
    });
    this.selectedPermission = null;
    this.selectedAllPermissions = false;
    this.isDateModalOpen = false;
    this.isTimeModalOpen = false;
  }

  onWillPresentDate(event: Event) {
    console.log(this.selectedPermission, "permission");
    console.log(this.selectedAllPermissions, "boolean");
  }

  onWillPresentTime(event: Event) {
    console.log(this.selectedPermission, "permission");
    console.log(this.selectedAllPermissions, "boolean");
  }

  PermChosenForDateEdit(permission: Permission, all: boolean) {
    this.selectedAllPermissions = all;
    this.selectedPermission = permission;
    this.isDateModalOpen = true;
    if (!all) {
      this.permissionDateForm.patchValue({
        startDate: this.datepipe.transform(
          new Date(this.selectedPermission.work_start_date),
          "yyyy-MM-dd"
        ),
        endDate: this.datepipe.transform(
          new Date(this.selectedPermission.work_end_date),
          "yyyy-MM-dd"
        ),
        workingDays: this.selectedPermission.working_days.split(","),
      });
    } else {
      this.permissionDateForm.patchValue({
        startDate: this.datepipe.transform(new Date(), "yyyy-MM-dd"),
        endDate: this.datepipe.transform(new Date(), "yyyy-MM-dd"),
        workingDays: [],
      });
    }
  }

  PermChosenForTimeEdit(permission: Permission, all: boolean) {
    this.selectedAllPermissions = all;
    this.selectedPermission = permission;
    this.isTimeModalOpen = true;
    if (!all) {
      this.permissionTimeForm.patchValue({
        startTime: permission.work_start_time,
        endTime: permission.work_end_time,
      });
    } else {
      this.permissionTimeForm.patchValue({
        startTime: "00:00",
        endTime: "23:59",
      });
    }
  }

  get permissionDateFormControls() {
    return this.permissionDateForm.controls;
  }

  get permissionTimeFormControls() {
    return this.permissionTimeForm.controls;
  }

  checkAllUserEnable(permissions: Permission[]): boolean {
    return permissions.every((item) => item.permission == 1);
  }
  checkAllUserDisable(permissions: Permission[]): boolean {
    return permissions.every((item) => item.permission == 0);
  }
  changePaginationPage = (newPage: number): void => {
    this.userPage = newPage;
  };
}
